const threshold = 3;
const allItems = $input.all();

// Group by apartment
const byApt = {};
for (const item of allItems) {
  const apt = item.json.apartment_id;
  if (!byApt[apt]) {
    byApt[apt] = { name: item.json.apartment_name, base_price: item.json.base_price, bookings: [] };
  }
  byApt[apt].bookings.push({
    id: item.json.booking_id,
    checkin: item.json.checkin_at,
    checkout: item.json.checkout_at
  });
}

const gaps = [];
const today = new Date();
today.setHours(0,0,0,0);

for (const [aptId, data] of Object.entries(byApt)) {
  const sorted = data.bookings.sort((a, b) => new Date(a.checkin) - new Date(b.checkin));
  for (let i = 0; i < sorted.length - 1; i++) {
    const prev = sorted[i];
    const next = sorted[i + 1];
    const gapStart = new Date(prev.checkout);
    const gapEnd   = new Date(next.checkin);
    const nights = Math.round((gapEnd - gapStart) / 86400000);
    if (nights >= 1 && nights <= threshold && gapStart >= today) {
      const bp = data.base_price ? Number(data.base_price) : null;
      const rec = nights === 1
        ? 'Продать как короткое окно / спеццена / разрешить 1 ночь'
        : nights === 2
          ? 'Спеццена на 2 ночи / подсветить владельцу'
          : 'Можно продать как короткий заезд или держать min stay';
      gaps.push({
        apartment_id: aptId,
        gap_start: gapStart.toISOString().split('T')[0],
        gap_end:   gapEnd.toISOString().split('T')[0],
        nights,
        previous_booking_id: prev.id,
        next_booking_id:     next.id,
        estimated_loss: bp ? nights * bp : null,
        recommendation: rec
      });
    }
  }
}

if (gaps.length === 0) {
  return [{ json: { _no_gaps: true, message: 'No small gap windows found' } }];
}
return gaps.map(g => ({ json: g }));
